<style>
html { margin: 0 !important; padding: 0 !important; top: 0 !important; }
html.translated-ltr, html.translated-rtl { margin: 0 !important; padding: 0 !important; top: 0 !important; }
body { margin: 0 !important; padding: 0 !important; top: 0 !important; position: static !important; }
#wpadminbar { display: none !important; }
.goog-te-banner-frame,
.goog-te-banner-frame.skiptranslate,
iframe.goog-te-banner-frame { display: none !important; height: 0 !important; }
.skiptranslate > iframe { display: none !important; }
#goog-gt-tt, .goog-te-balloon-frame { display: none !important; }

/* Custom cursor — mouse/trackpad only, never on touch */
@media (hover: hover) and (pointer: fine) {
    * { cursor: none !important; }
}
.custom-cursor {
    position: fixed;
    top: 0;
    left: 0;
    width: 22px;
    height: 22px;
    border: 2px solid red;
    background: rgba(255, 0, 0, 0.15);
    pointer-events: none;
    z-index: 999999;
    transform: translate(-50%, -50%) scale(1);
    border-radius: 50%;
    transition: transform 0.3s ease, box-shadow 0.3s ease, background 0.3s ease;
    animation: cursorAmoeba 2s infinite ease-in-out;
    box-shadow: 0 0 10px rgba(255, 0, 0, 0.5), 0 0 20px rgba(255, 0, 0, 0.25);
}
/* Hide the cursor dot on touch screens */
@media (hover: none), (pointer: coarse) {
    .custom-cursor { display: none !important; }
}
.custom-cursor.paused {
    transform: translate(-50%, -50%) scale(1.5);
    background: rgba(255, 0, 0, 0.3);
    box-shadow: 0 0 18px rgba(255, 0, 0, 0.7), 0 0 36px rgba(255, 0, 0, 0.4);
}
@keyframes cursorAmoeba {
    0%   { border-radius: 40% 60% 60% 40% / 40% 40% 60% 60%; }
    25%  { border-radius: 60% 40% 30% 70% / 50% 60% 40% 50%; }
    50%  { border-radius: 70% 30% 40% 60% / 60% 40% 50% 50%; }
    75%  { border-radius: 30% 70% 60% 40% / 60% 50% 50% 60%; }
    100% { border-radius: 40% 60% 60% 40% / 40% 40% 60% 60%; }
}

/* ── Custom Language Switcher Bar ── */
#ot-lang-bar {
    background: #ffffff;
    padding: 5px 16px;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    position: relative;
    z-index: 10000;
    border-bottom: 1px solid #e8e8e8;
}
#ot-lang-btn {
    display: inline-flex;
    align-items: center;
    gap: 7px;
    background: transparent;
    border: 1px solid #ddd;
    color: #333;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 0.4px;
    padding: 5px 13px;
    border-radius: 20px;
    cursor: pointer;
